import React from 'react'
import c from './appointments.module.scss'
import { API } from '../../api'

const Appointments = () => {
  const [ appointments, setAppointments ] = React.useState(null)
  const [ workers, setWorkers ] = React.useState(null)

  const date = new Date()
  const todayDate = `${date.getFullYear()}-${(date.getMonth() + 1) < 10 ? `0${date.getMonth() + 1}` : date.getMonth() + 1}-${date.getDate()}`


  React.useEffect(() => {
    API.getWorkers()
      .then(res => {
        const workersData = res.data;
        setWorkers(workersData);

        const workerNames = workersData.map(worker => worker.name);

        API.getClients().then(res => {
          const result = res.data.filter(client => {
            return client.services.some(service =>
              service.appointment_date === todayDate &&
              workerNames.includes(service.name)
            );
          });

          setAppointments(result);
        });
      });
  }, []);



  return (
    <div className={c.appointments}>
      <div className={c.header}>
        <h1>
          Записи сотрудников
        </h1>
        <span>
          14 марта
        </span>
      </div>

      <div className={c.workers}>
        <div className={c.worker}>
          <p>Кумушай</p>
          <div className={c.times}>
            <span>
              12:00 - Кавитанция
            </span>
            <span>
              12:00 - Кавитанция
            </span>
            <span>
              12:00 - Кавитанция
            </span>
          </div>
        </div>

        <div className={c.worker}>
          <p>Кумушай</p>
          <div className={c.times}>
            <span>
              12:00 - Кавитанция
            </span>
            <span>
              12:00 - Кавитанция
            </span>
            <span>
              12:00 - Кавитанция
            </span>
          </div>
        </div>
      </div>
    </div>
  )
}

export default Appointments
